class Stack:
    def __init__(self):
        self.items = []

    def push(self, value):
        self.items.append(value)

stack = Stack()
stack.push(10)
stack.push(20)
print(stack.items)

class Stack:
    def __init__(self):
        self.items = []

    def pop(self):
        if not self.items:
            raise IndexError("pop from empty stack")
        return self.items.pop()

stack = Stack()
stack.items = [10, 20, 30]
print(stack.pop())

